import{_ as a,c as i,o as s,a1 as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Recuperación por Compresión: Recuperación Automática de Habilidades | opencode-agent-skills","description":"Aprende el mecanismo de recuperación por compresión de opencode-agent-skills. Restaura automáticamente la lista de habilidades después de la compresión de sesión, usando mensajes sintéticos para mantener las habilidades disponibles.","frontmatter":{"title":"Recuperación por Compresión: Recuperación Automática de Habilidades | opencode-agent-skills","sidebarTitle":"Habilidades no se pierden tras compresión","subtitle":"Recuperación por Compresión: Recuperación Automática de Habilidades","description":"Aprende el mecanismo de recuperación por compresión de opencode-agent-skills. Restaura automáticamente la lista de habilidades después de la compresión de sesión, usando mensajes sintéticos para mantener las habilidades disponibles.","tags":["Gestión de contexto","Persistencia de sesión","Funcionalidad avanzada"],"prerequisite":["platforms-loading-skills-into-context"],"order":4},"headers":[],"relativePath":"es/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md","filePath":"es/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"}'),o={name:"es/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"};function t(l,e,r,d,c,p){return s(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="mecanismo-de-recuperacion-por-compresion-de-contexto" tabindex="-1">Mecanismo de Recuperación por Compresión de Contexto <a class="header-anchor" href="#mecanismo-de-recuperacion-por-compresion-de-contexto" aria-label="Permalink to &quot;Mecanismo de Recuperación por Compresión de Contexto&quot;">​</a></h1><h2 id="lo-que-podras-hacer-despues-de-aprender" tabindex="-1">Lo que podrás hacer después de aprender <a class="header-anchor" href="#lo-que-podras-hacer-despues-de-aprender" aria-label="Permalink to &quot;Lo que podrás hacer después de aprender&quot;">​</a></h2><ul><li>Entender cómo el complemento mantiene las habilidades disponibles después de la compresión de sesión</li><li>Conocer los momentos de activación y el flujo de ejecución de la recuperación por compresión</li><li>Poder verificar si la recuperación por compresión funciona correctamente</li><li>Entender el papel de los mensajes sintéticos en el mecanismo de recuperación</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>En sesiones largas, OpenCode ejecutará <strong>Compresión de Contexto</strong> para ahorrar tokens. Después de la compresión, la sesión solo conserva los mensajes más recientes, y el historial temprano (incluido el contenido de las habilidades inyectadas anteriormente) se eliminará.</p><p>Esto causa un problema: si el contenido de las habilidades se comprime, la IA ya no sabrá qué habilidades están disponibles y no podrá usar las habilidades cargadas.</p><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p>El mecanismo de recuperación por compresión se ejecuta <strong>automáticamente</strong>, no necesitas intervención manual. Pero después de entender su principio, puedes solucionar problemas en los siguientes escenarios:</p><ul><li>La IA de repente &quot;olvida&quot; las habilidades en una sesión larga</li><li>Necesitas depurar la disponibilidad de habilidades después de la compresión</li><li>Quieres entender la estrategia de gestión de sesiones del complemento</li></ul><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><h3 id="¿que-es-la-compresion-de-contexto" tabindex="-1">¿Qué es la compresión de contexto? <a class="header-anchor" href="#¿que-es-la-compresion-de-contexto" aria-label="Permalink to &quot;¿Qué es la compresión de contexto?&quot;">​</a></h3><p>A medida que aumenta la cantidad de mensajes, la sesión de OpenCode se vuelve más larga. Cuando el uso de tokens se acerca al límite, el sistema ejecutará automáticamente <strong>compresión de contexto</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Inicio de sesión] → [Mensaje 1] → [Mensaje 2] → ... → [Mensaje 50]</span></span>
<span class="line"><span>                           ↑ Punto de compresión: solo conserva los 10 mensajes más recientes</span></span></code></pre></div><p>Después de la compresión, los mensajes tempranos (incluido el contenido de inyección de habilidades) se eliminarán, y la IA solo podrá ver el historial de mensajes reciente.</p><h3 id="como-funciona-el-mecanismo-de-recuperacion-por-compresion" tabindex="-1">Cómo funciona el mecanismo de recuperación por compresión <a class="header-anchor" href="#como-funciona-el-mecanismo-de-recuperacion-por-compresion" aria-label="Permalink to &quot;Cómo funciona el mecanismo de recuperación por compresión&quot;">​</a></h3><p>El complemento escucha el evento <code>session.compacted</code>, y una vez que detecta que ocurrió la compresión, ejecuta inmediatamente las siguientes operaciones de recuperación:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Se activa la compresión de sesión] --&gt; B[Evento session.compacted]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{¿Superpowers activado?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Sí| D[Reinyectar prompt de Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|No| E[Omitir Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[Reinyectar lista de habilidades]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[Vaciar registro de habilidades cargadas]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Recuperación completada]</span></span></code></pre></div><p><strong>Puntos clave</strong>:</p><ul><li>La recuperación es <strong>automática</strong>, no requiere activación manual</li><li>La lista de habilidades recuperada incluye <strong>todas las habilidades descubiertas</strong> (no solo las cargadas anteriormente)</li><li>El registro de habilidades cargadas se vaciará, permitiendo que la IA reevalúe qué habilidades necesita</li></ul><h3 id="rol-de-los-mensajes-sinteticos" tabindex="-1">Rol de los mensajes sintéticos <a class="header-anchor" href="#rol-de-los-mensajes-sinteticos" aria-label="Permalink to &quot;Rol de los mensajes sintéticos&quot;">​</a></h3><p>El complemento usa el mecanismo de <strong>Inyección de Mensajes Sintéticos</strong> para inyectar contenido:</p><table tabindex="0"><thead><tr><th>Atributo</th><th>Valor</th><th>Significado</th></tr></thead><tbody><tr><td><code>noReply</code></td><td><code>true</code></td><td>La IA no responderá al contenido inyectado en sí mismo</td></tr><tr><td><code>synthetic</code></td><td><code>true</code></td><td>Marca como contenido generado por el sistema, no cuenta como entrada del usuario, no se muestra en la UI</td></tr></tbody></table><p>Esto significa que el contenido inyectado por la recuperación por compresión:</p><ul><li>Es completamente transparente para el usuario (no visible)</li><li>No consume cuota de mensajes del usuario</li><li>Pero será leído y entendido por la IA</li></ul><h2 id="🎒-preparativos" tabindex="-1">🎒 Preparativos <a class="header-anchor" href="#🎒-preparativos" aria-label="Permalink to &quot;🎒 Preparativos&quot;">​</a></h2><p>Este tutorial requiere:</p><ul><li>Complemento OpenCode Agent Skills instalado</li><li>Conocimiento básico de carga de habilidades</li><li>Una sesión larga para probar el efecto de compresión</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>No se requiere preparación adicional, el mecanismo de recuperación por compresión es una función incorporada del complemento.</p></div><h2 id="sigueme-verifica-el-efecto-de-recuperacion-por-compresion" tabindex="-1">Sígueme: Verifica el efecto de recuperación por compresión <a class="header-anchor" href="#sigueme-verifica-el-efecto-de-recuperacion-por-compresion" aria-label="Permalink to &quot;Sígueme: Verifica el efecto de recuperación por compresión&quot;">​</a></h2><h3 id="paso-1-inicia-una-nueva-sesion" tabindex="-1">Paso 1: Inicia una nueva sesión <a class="header-anchor" href="#paso-1-inicia-una-nueva-sesion" aria-label="Permalink to &quot;Paso 1: Inicia una nueva sesión&quot;">​</a></h3><p><strong>Por qué</strong> Verificar que la lista de habilidades se inyecte normalmente durante la inicialización de la sesión</p><p>Inicia una nueva sesión e introduce cualquier mensaje:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hola</span></span></code></pre></div><p><strong>Deberías ver</strong>: La IA responde normalmente, y en segundo plano inyecta automáticamente la lista de habilidades (invisible para el usuario)</p><h3 id="paso-2-carga-una-habilidad" tabindex="-1">Paso 2: Carga una habilidad <a class="header-anchor" href="#paso-2-carga-una-habilidad" aria-label="Permalink to &quot;Paso 2: Carga una habilidad&quot;">​</a></h3><p><strong>Por qué</strong> Asegurar que el contenido de la habilidad se inyecte en el contexto</p><p>Llama a la herramienta <code>use_skill</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usa get_available_skills para ver las habilidades disponibles, luego usa use_skill para cargar una de ellas</span></span></code></pre></div><p><strong>Deberías ver</strong>: La IA lista las habilidades disponibles, luego carga la habilidad que elegiste</p><h3 id="paso-3-activa-la-compresion-de-contexto" tabindex="-1">Paso 3: Activa la compresión de contexto <a class="header-anchor" href="#paso-3-activa-la-compresion-de-contexto" aria-label="Permalink to &quot;Paso 3: Activa la compresión de contexto&quot;">​</a></h3><p><strong>Por qué</strong> Simular escenario de sesión larga, activar el mecanismo de compresión de OpenCode</p><p>Envía mensajes continuamente, simulando una conversación larga:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mensaje 1: contenido de prueba</span></span>
<span class="line"><span>Mensaje 2: continuar probando</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(Repetir enviando 20-30 mensajes)</span></span></code></pre></div><p><strong>Deberías ver</strong>:</p><ul><li>A medida que aumentan los mensajes, el historial de la sesión se alarga</li><li>Al alcanzar cierta longitud, OpenCode ejecuta automáticamente la compresión</li><li>Después de la compresión, los mensajes tempranos (incluida la inyección de habilidades) se eliminan</li></ul><h3 id="paso-4-verifica-el-efecto-de-recuperacion" tabindex="-1">Paso 4: Verifica el efecto de recuperación <a class="header-anchor" href="#paso-4-verifica-el-efecto-de-recuperacion" aria-label="Permalink to &quot;Paso 4: Verifica el efecto de recuperación&quot;">​</a></h3><p><strong>Por qué</strong> Verificar que la lista de habilidades se reinyecte después de la compresión</p><p>Después de la compresión, haz que la IA use habilidades nuevamente:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ayúdame a usar la habilidad git-helper para crear una nueva rama (asumiendo que ya instalaste la habilidad git-helper)</span></span></code></pre></div><p><strong>Deberías ver</strong>:</p><ul><li>La IA aún sabe qué habilidades están disponibles (prueba que la lista de habilidades se ha recuperado)</li><li>La IA puede cargar y usar habilidades normalmente (prueba que la funcionalidad de habilidades no se vio afectada por la compresión)</li></ul><h3 id="paso-5-verifica-la-inyeccion-de-mensajes-sinteticos" tabindex="-1">Paso 5: Verifica la inyección de mensajes sintéticos <a class="header-anchor" href="#paso-5-verifica-la-inyeccion-de-mensajes-sinteticos" aria-label="Permalink to &quot;Paso 5: Verifica la inyección de mensajes sintéticos&quot;">​</a></h3><p><strong>Por qué</strong> Confirmar que el mecanismo de recuperación usa mensajes sintéticos, sin interferir con la conversación</p><p>Si el complemento lo admite, puedes verificar el historial de mensajes de la sesión (dependiendo de la funcionalidad de OpenCode):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usa herramientas de depuración para ver el historial de mensajes de la sesión</span></span></code></pre></div><p><strong>Deberías ver</strong>:</p><ul><li>Los mensajes de la lista de habilidades recuperados están marcados como <code>synthetic: true</code></li><li>Estos mensajes no se muestran en la interfaz de conversación normal</li></ul><h2 id="punto-de-verificacion-✅" tabindex="-1">Punto de verificación ✅ <a class="header-anchor" href="#punto-de-verificacion-✅" aria-label="Permalink to &quot;Punto de verificación ✅&quot;">​</a></h2><p>Después de completar los pasos anteriores, deberías poder confirmar:</p><ul><li>[ ] La IA aún puede acceder a la lista de habilidades en sesiones largas</li><li>[ ] La función de carga de habilidades funciona normalmente después de la compresión</li><li>[ ] El proceso de recuperación es completamente transparente para el usuario</li></ul><h2 id="advertencias-de-problemas" tabindex="-1">Advertencias de problemas <a class="header-anchor" href="#advertencias-de-problemas" aria-label="Permalink to &quot;Advertencias de problemas&quot;">​</a></h2><h3 id="problema-1-despues-de-la-compresion-la-ia-dice-no-encuentra-habilidades" tabindex="-1">Problema 1: Después de la compresión, la IA dice &quot;no encuentra habilidades&quot; <a class="header-anchor" href="#problema-1-despues-de-la-compresion-la-ia-dice-no-encuentra-habilidades" aria-label="Permalink to &quot;Problema 1: Después de la compresión, la IA dice &quot;no encuentra habilidades&quot;&quot;">​</a></h3><p><strong>Posibles causas</strong>:</p><ul><li>El complemento no está escuchando correctamente el evento <code>session.compacted</code></li><li>La ruta del directorio de habilidades ha cambiado</li></ul><p><strong>Métodos de solución</strong>:</p><ol><li><p><strong>Verificar si se activa el evento de compresión</strong></p><ul><li>A través de los pasos 3 y 4 de &quot;Sígueme&quot;, confirma que la IA aún puede acceder a la lista de habilidades después de la compresión</li><li>Si la IA puede usar habilidades normalmente, significa que el mecanismo de recuperación por compresión funciona correctamente</li></ul></li><li><p><strong>Verificar si el complemento está cargado correctamente</strong></p><ul><li>Reinicia OpenCode</li><li>Después de iniciar una nueva sesión, haz que la IA liste las habilidades disponibles (<code>get_available_skills</code>)</li><li>Si puedes ver la lista de habilidades, significa que el complemento está cargado correctamente</li></ul></li></ol><h3 id="problema-2-la-lista-de-habilidades-recuperada-esta-vacia" tabindex="-1">Problema 2: La lista de habilidades recuperada está vacía <a class="header-anchor" href="#problema-2-la-lista-de-habilidades-recuperada-esta-vacia" aria-label="Permalink to &quot;Problema 2: La lista de habilidades recuperada está vacía&quot;">​</a></h3><p><strong>Posibles causas</strong>:</p><ul><li>No hay habilidades en la ruta de descubrimiento de habilidades</li><li>Formato de archivo de habilidades incorrecto</li></ul><p><strong>Métodos de solución</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Consultar manualmente las habilidades disponibles</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Usa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_available_skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> para</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lista</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> de</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> habilidades</span></span></code></pre></div><p>Si devuelve una lista vacía, verifica el directorio de habilidades y el formato de los archivos.</p><h3 id="problema-3-el-estado-de-habilidades-cargadas-se-pierde-despues-de-la-compresion" tabindex="-1">Problema 3: El estado de habilidades cargadas se pierde después de la compresión <a class="header-anchor" href="#problema-3-el-estado-de-habilidades-cargadas-se-pierde-despues-de-la-compresion" aria-label="Permalink to &quot;Problema 3: El estado de habilidades cargadas se pierde después de la compresión&quot;">​</a></h3><p><strong>Este es un comportamiento esperado</strong>, no es un Bug. El mecanismo de recuperación vaciará el registro <code>loadedSkillsPerSession</code>, permitiendo que la IA reevalúe qué habilidades necesita.</p><p><strong>Método de solución</strong>: La IA decidirá automáticamente si recargar las habilidades según el contexto, sin intervención manual.</p><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><p>El mecanismo de recuperación por compresión asegura la disponibilidad de habilidades en sesiones largas de las siguientes formas:</p><ol><li><strong>Escuchar eventos de compresión</strong>: Detectar automáticamente el evento <code>session.compacted</code></li><li><strong>Reinyectar lista de habilidades</strong>: Inyectar todas las habilidades usando la etiqueta <code>&lt;available-skills&gt;</code></li><li><strong>Recuperación opcional de Superpowers</strong>: Si está activado, restaurar simultáneamente el prompt de Superpowers</li><li><strong>Usar mensajes sintéticos</strong>: El proceso de recuperación es transparente para el usuario, no afecta la conversación</li><li><strong>Restablecer registro cargado</strong>: Vaciar el conjunto de habilidades cargadas, permitir reevaluación</li></ol><p>Este mecanismo asegura que:</p><ul><li>Las habilidades siempre estén disponibles en sesiones largas</li><li>El proceso de recuperación sea automático y sin percepción</li><li>La IA pueda decidir qué habilidades usar según el contexto más reciente</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../../faq/troubleshooting/">Solución de problemas</a></strong>.</p><p>Aprenderás:</p><ul><li>Métodos para manejar errores y excepciones comunes</li><li>Técnicas de solución de problemas relacionadas con la recuperación por compresión</li><li>Soluciones para otros problemas de uso</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de código fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Ruta de archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>Escucha de evento de compresión</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L157" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-157</td></tr><tr><td>Inicialización de primer mensaje</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L70-L105" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>70-105</td></tr><tr><td>Inyección de lista de habilidades</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L345-L370" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>345-370</td></tr><tr><td>Inyección de mensajes sintéticos</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Gestión de estado de sesión</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L25-L35" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>25-35</td></tr></tbody></table><p><strong>Variables clave</strong>:</p><ul><li><code>setupCompleteSessions: Set&lt;string&gt;</code>: Registra los IDs de sesión que completaron la inicialización</li><li><code>loadedSkillsPerSession: Map&lt;string, Set&lt;string&gt;&gt;</code>: Registra los nombres de habilidades cargadas para cada sesión</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>injectSkillsList()</code>: Inyecta la lista de habilidades disponibles en la sesión</li><li><code>injectSyntheticContent()</code>: Inyecta contenido usando mensajes sintéticos</li><li><code>getSessionContext()</code>: Obtiene información de modelo y agente de la sesión</li></ul></details>`,85)])])}const h=a(o,[["render",t]]);export{m as __pageData,h as default};
